"use client";

import { Container } from "@/components/layout/Container";
import { HeroVisual } from "@/components/hero/HeroVisual";
import { ArrowRight, ArrowUpRight, Mouse } from "lucide-react";
import { useEffect, useRef } from "react";
import { useReducedMotion } from "framer-motion";
import { gsap } from "@/lib/gsap";

export function HeroSection() {
  const rootRef = useRef<HTMLElement | null>(null);
  const reducedMotion = useReducedMotion();

  useEffect(() => {
    if (reducedMotion) return;
    const ctx = gsap.context(() => {
      const tl = gsap.timeline({ defaults: { ease: "power3.out" } });
      tl.from(".hero-role", { opacity: 0, y: 10, duration: 0.55 })
        .from(".hero-role span", { scaleX: 0, transformOrigin: "left center", duration: 0.45 }, "<")
        .from(".hero-line > span", { yPercent: 105, duration: 0.9, stagger: 0.12 }, "-=.12")
        .from(".hero-heading-accent > span", { opacity: 0, scale: 0.94, duration: 0.8 }, "<.18")
        .from(".hero-description", { opacity: 0, y: 18, duration: 0.7 }, "-=.3")
        .from(".hero-actions > *", { opacity: 0, y: 14, duration: 0.55, stagger: 0.12 }, "-=.38")
        .from(".hero-laptop", { opacity: 0, x: 70, scale: 0.92, rotateY: -8, duration: 1.15, ease: "expo.out" }, "<.05")
        .from(".tech-badge", { opacity: 0, y: 20, scale: 0.8, duration: 0.55, stagger: 0.1 }, "<.2")
        .from(".scroll-indicator", { opacity: 0, y: 10, duration: 0.5 }, "-=.2");
    }, rootRef);
    return () => ctx.revert();
  }, [reducedMotion]);

  return (
    <section ref={rootRef} id="home" className="hero" aria-labelledby="hero-title">
      <Container className="hero-grid">
        <div className="hero-content">
          <p className="eyebrow hero-role"><span />Full Stack Developer</p>
          <h1 id="hero-title" className="hero-heading">
            <span className="hero-line"><span>I Build</span></span>
            <span className="hero-line hero-heading-accent"><span>Intelligent</span></span>
            <span className="hero-line"><span>Web Experiences</span></span>
          </h1>
          <p className="hero-description">Full Stack Developer passionate about AI, building scalable SaaS products and delivering impactful digital experiences.</p>
          <div className="hero-actions">
            <a className="hero-button hero-button-primary" href="#projects">View My Work <ArrowUpRight aria-hidden="true" size={17} /></a>
            <a className="hero-button hero-button-secondary" href="#contact">Let&apos;s Connect <ArrowRight aria-hidden="true" size={17} /></a>
          </div>
        </div>
        <HeroVisual />
        <div className="scroll-indicator"><Mouse aria-hidden="true" size={19} /><span>Scroll Down</span></div>
      </Container>
    </section>
  );
}
