"use client";

import { Container } from "@/components/layout/Container";
import { projects } from "@/data/projects";
import { ProjectCard } from "@/components/projects/ProjectCard";
import { CareerAIVisual } from "@/components/projects/CareerAIVisual";
import { SyncSpaceVisual } from "@/components/projects/SyncSpaceVisual";
import { useEffect, useRef } from "react";
import { useReducedMotion } from "framer-motion";
import { gsap, setupScrollTrigger } from "@/lib/gsap";

export function SelectedWork() {
  const rootRef = useRef<HTMLElement | null>(null);
  const reducedMotion = useReducedMotion();

  useEffect(() => {
    if (typeof window === "undefined" || reducedMotion) return;
    setupScrollTrigger();
    const ctx = gsap.context(() => {
      const tl = gsap.timeline({
        scrollTrigger: {
          trigger: rootRef.current,
          start: "top 76%",
          once: true,
        },
      });

      tl.from(".selected-work__header p", { opacity: 0, y: 12, duration: 0.55, ease: "power3.out" });
      tl.from(".selected-work__header h2", { opacity: 0, yPercent: 100, duration: 0.8, ease: "power4.out" }, "-=.18");
      tl.from(".project-card--left", { opacity: 0, x: -80, duration: 1, ease: "power3.out" }, "-=.12");
      tl.from(".project-card--right", { opacity: 0, x: 80, duration: 1, ease: "power3.out" }, "<.12");
      gsap.to(".project-card__visual", { yPercent: -3, ease: "none", scrollTrigger: { trigger: rootRef.current, start: "top bottom", end: "bottom top", scrub: 0.7 } });
    }, rootRef);

    return () => ctx.revert();
  }, [reducedMotion]);

  return (
    <section ref={rootRef} id="projects" className="section selected-work" aria-labelledby="work-title">
      <Container>
        <div className="selected-work__header">
          <div>
            <p className="eyebrow">Featured Work</p>
            <h2 id="work-title">Selected Work</h2>
          </div>
          <div className="explore-link">Explore all projects →</div>
        </div>

        <div className="project-grid">
          <ProjectCard project={projects[0]} variant="left">
            <CareerAIVisual />
          </ProjectCard>

          <ProjectCard project={projects[1]} variant="right">
            <SyncSpaceVisual />
          </ProjectCard>
        </div>
      </Container>
    </section>
  );
}
